import React, { useState, useEffect } from 'react';
import { 
  LayoutDashboard, FileSpreadsheet, Bot, Settings, Play, Download, 
  AlertCircle, CheckCircle2, CalendarDays, ClipboardPaste, Loader2,
  Database, Building2, Cpu, CalendarClock, Plus, Trash2, Save
} from 'lucide-react';

export default function App() {
  const [activeTab, setActiveTab] = useState('fcst');
  const [fcstInput, setFcstInput] = useState('');
  const [sompInput, setSompInput] = useState('');
  const [results, setResults] = useState([]);
  const [status, setStatus] = useState({ type: 'idle', message: '' });

  // 기본 마스터 데이터 (초기화용)
  const defaultRules = {
    lineMap: { 
      'T1': 'SEC-T1(USA)', 'P1D': 'SEC-P1(D)(KR)', 'P1F': 'SEC-P1(F)(KR)',
      'P2D': 'SEC-P2(D)(KR)', 'P2F': 'SEC-P2(F)(KR)', 'P3F': 'SEC-P3(F)(KR)',
      'P4D': 'SEC-P4(D)(KR)', 'P4H': 'SEC-P4(H)(KR)', 'X2': 'SEC-X2L(CN)'
    },
    fabClientMap: {
      'SEC-T1(USA)': 'Samsung Electronics', 'SAS-S6(USA)': 'Samsung Electronics',
      'SEC-NRDk(KR)': 'Samsung Electronics', 'SEC-P1(D)(KR)': 'Samsung Electronics',
      'SEC-P1(F)(KR)': 'Samsung Electronics', 'SEC-P2(D)(KR)': 'Samsung Electronics',
      'SEC-P2(F)(KR)': 'Samsung Electronics', 'SEC-P3(F)(KR)': 'Samsung Electronics',
      'SEC-P4(D)(KR)': 'Samsung Electronics', 'SEC-P4(H)(KR)': 'Samsung Electronics',
      'SEC-X2L(CN)': 'Samsung Electronics',
      'SK hynix-C2(CN)': 'SK Hynix', 'SK hynix-M12(KR)': 'SK Hynix',
      'SK hynix-M14 P-II(KR)': 'SK Hynix', 'SK hynix-M15 P-II(KR)': 'SK Hynix',
      'SK hynix-M15X(KR)': 'SK Hynix', 'SK hynix-M16(KR)': 'SK Hynix'
    },
    modelMap: { 
      'SUPRA-N-M': { model: 'SUPRA Nm (J)', pm: 0 }, 
      'SUPRA-N': { model: 'SUPRA N', pm: 0 },
      'ASH_MTL_200_SUPRA': { model: 'SUPRA N', pm: 0 },
      'ASH_MTL_250_CUT': { model: 'SUPRA N', pm: 0 },
      'ZEDIUS-XP (JEP)': { model: 'ZEDIUS-XP', pm: 0 }
    },
    atmMaster: [
      { id: 'ATM-102', start: '2026-01-13', end: '2026-01-29', maxCapa: 6 },
      { id: 'ATM-104', start: '2026-01-29', end: '2026-02-19', maxCapa: 6 },
      { id: 'ATM-108', start: '2026-03-10', end: '2026-03-26', maxCapa: 6 },
      { id: 'ATM-112', start: '2026-04-13', end: '2026-04-29', maxCapa: 6 },
      { id: 'ATM-115', start: '2026-05-11', end: '2026-05-28', maxCapa: 6 },
      { id: 'ATM-122', start: '2026-07-12', end: '2026-07-28', maxCapa: 6 },
      { id: 'ATM-125', start: '2026-08-05', end: '2026-08-24', maxCapa: 6 },
      { id: 'ATM-129', start: '2026-09-09', end: '2026-09-29', maxCapa: 6 },
      { id: 'ATM-132', start: '2026-10-11', end: '2026-10-27', maxCapa: 6 },
      { id: 'ATM-135', start: '2026-11-04', end: '2026-11-22', maxCapa: 6 }
    ]
  };

  const [mappingRules, setMappingRules] = useState(() => {
    const saved = localStorage.getItem('pskMasterData');
    return saved ? JSON.parse(saved) : defaultRules;
  });

  const saveRules = (newRules) => {
    setMappingRules(newRules);
    localStorage.setItem('pskMasterData', JSON.stringify(newRules));
  };

  const [newLine, setNewLine] = useState({ client: '', line: '', fab: '' });
  const [newModel, setNewModel] = useState({ raw: '', somp: '', pm: 0 });
  const [newAtm, setNewAtm] = useState({ id: '', start: '', end: '', capa: 6 });

  // ---------------------------------------------------------
  // 데이터 병합 및 배정 로직 (FCST 탭)
  // ---------------------------------------------------------
  const processData = () => {
    setStatus({ type: 'loading', message: '마스터 데이터 매칭 및 가동률 스캔 중...' });
    setResults([]);

    setTimeout(() => {
      try {
        const fcstRows = fcstInput.trim().split('\n');
        const processed = [];
        let successCount = 0; let failCount = 0;

        // 1. SOMP 데이터에서 현재 ATM 가동률(로드) 파악
        const atmLoad = {};
        mappingRules.atmMaster.forEach(atm => { atmLoad[atm.id] = 0; });

        const sompRows = sompInput.trim().split('\n');
        sompRows.forEach(row => {
          const cols = row.split(/\t+| {2,}/).map(c => c.trim());
          cols.forEach(c => {
            if (c.startsWith('ATM-') && atmLoad[c] !== undefined) {
              atmLoad[c]++; // 기존 배정 이력 카운트
            }
          });
        });

        // 2. 신규 FCST 데이터 파싱 및 배정
        fcstRows.forEach((row, idx) => {
          const cols = row.split(/\t+| {2,}/).map(c => c.trim());
          const isNew = cols.some(c => c && c.includes('신규'));

          if (isNew) {
            // 라인 및 모델명 마스터 탐색
            const rawLine = Object.keys(mappingRules.lineMap).find(key => cols.includes(key));
            const rawModel = Object.keys(mappingRules.modelMap).find(key => cols.includes(key));

            // 수량 추출
            const qtyStr = cols.find(c => /^\d{1,3}$/.test(c));
            const qty = qtyStr ? parseInt(qtyStr) : 1;

            // 납기일 추출
            const dateMatches = cols.filter(c => /^\d{4}[-.]\d{2}[-.]\d{2}/.test(c));
            const rawDate = dateMatches.length > 0 ? dateMatches[dateMatches.length - 1] : '';
            const reqDate = rawDate.replace(/\./g, '-');

            // [수정됨] 매칭 실패 시 빈칸 처리
            const fabName = rawLine ? mappingRules.lineMap[rawLine] : '';
            const clientName = fabName ? (mappingRules.fabClientMap[fabName] || '') : '';
            const modelInfo = rawModel ? mappingRules.modelMap[rawModel] : { model: '', pm: '' };

            if (!rawLine || !rawModel) failCount++;

            let reqDateObj = reqDate ? new Date(reqDate) : null;

            // 수량만큼 행을 분할하면서 배정 및 Capa 체크 로직 수행
            for(let i=0; i<qty; i++) {
              let assignedAtm = '';
              let prodEndDate = ''; 
              let shipAvailableDate = ''; 
              let finalReqDate = ''; 
              let remarksArr = [];

              // 비고란에 간략한 에러 내용 기록
              if (!rawLine) remarksArr.push('라인 미등록');
              if (!rawModel) remarksArr.push('모델 미등록');
              if (!reqDate) remarksArr.push('납품일 누락');

              // 스케줄 검색
              if (reqDateObj) {
                const matchedAtm = mappingRules.atmMaster.find(atm => {
                  const startDate = new Date(atm.start);
                  const endDate = new Date(atm.end);
                  return reqDateObj >= startDate && reqDateObj <= endDate;
                });

                if (matchedAtm) {
                  assignedAtm = matchedAtm.id;
                  prodEndDate = matchedAtm.end; 
                  shipAvailableDate = matchedAtm.end; 
                  finalReqDate = reqDate;

                  // [수정됨] Capa 체크 및 경고 표출
                  if (atmLoad[matchedAtm.id] >= matchedAtm.maxCapa) {
                    remarksArr.push(`Capa 초과 (${atmLoad[matchedAtm.id] + 1}/${matchedAtm.maxCapa})`);
                  }
                  // 현재 건 배정으로 해당 ATM 로드 +1 증가 (중복 배정 누적 방지)
                  atmLoad[matchedAtm.id]++;

                } else {
                  remarksArr.push('적합한 ATM 일정 없음');
                }
              }

              // 특별한 경고가 없으면 신규 자동배정 표출
              if (remarksArr.length === 0) remarksArr.push('신규 자동배정');

              processed.push({
                'W/O': '', 'S/N': '', '그룹': '',
                '고객사': clientName, 'FAB': fabName, 'PM': modelInfo.pm, '모델': modelInfo.model,
                '배정 LOT': assignedAtm, 'OEC 상태': '', 'Ref.Tool': '', 
                '비고': remarksArr.join(', '), // 에러 텍스트 병합
                '납품일': finalReqDate, '생산완료일': prodEndDate, '출하가능일': shipAvailableDate
              });
              successCount++;
            }
          }
        });

        if (successCount === 0) setStatus({ type: 'error', message: '"신규" 데이터가 감지되지 않았습니다. 형식을 확인해 주세요.' });
        else {
          setResults(processed);
          setStatus({ type: 'success', message: `총 ${successCount}건 배정 완료. (검토필요: ${failCount}건)` });
        }
      } catch (err) {
        setStatus({ type: 'error', message: '오류 발생: 데이터를 다시 확인해 주세요.' });
      }
    }, 800);
  };

  const downloadExcel = () => {
    if (results.length === 0) return;
    const headers = Object.keys(results[0]);
    const csvContent = "data:text/csv;charset=utf-8,\uFEFF" + [headers.join(","), ...results.map(r => Object.values(r).map(v => `"${v}"`).join(","))].join("\n");
    const link = document.createElement("a");
    link.setAttribute("href", encodeURI(csvContent));
    link.setAttribute("download", `SOMP_Upload_${new Date().toISOString().slice(0,10)}.csv`);
    document.body.appendChild(link);
    link.click();
  };

  // ---------------------------------------------------------
  // 마스터 데이터 편집 로직
  // ---------------------------------------------------------
  const addLineRule = () => {
    if(!newLine.line || !newLine.fab || !newLine.client) return alert('항목을 모두 입력해주세요.');
    const updated = { ...mappingRules };
    updated.lineMap[newLine.line] = newLine.fab;
    updated.fabClientMap[newLine.fab] = newLine.client;
    saveRules(updated);
    setNewLine({ client: '', line: '', fab: '' });
  };

  const removeLineRule = (line) => {
    const updated = { ...mappingRules };
    delete updated.lineMap[line];
    saveRules(updated);
  };

  const addModelRule = () => {
    if(!newModel.raw || !newModel.somp) return alert('항목을 모두 입력해주세요.');
    const updated = { ...mappingRules };
    updated.modelMap[newModel.raw] = { model: newModel.somp, pm: parseInt(newModel.pm) || 0 };
    saveRules(updated);
    setNewModel({ raw: '', somp: '', pm: 0 });
  };

  const removeModelRule = (raw) => {
    const updated = { ...mappingRules };
    delete updated.modelMap[raw];
    saveRules(updated);
  };

  const addAtmRule = () => {
    if(!newAtm.id || !newAtm.start || !newAtm.end) return alert('항목을 모두 입력해주세요.');
    const updated = { ...mappingRules };
    updated.atmMaster = [...updated.atmMaster, { ...newAtm, maxCapa: parseInt(newAtm.capa) || 6 }]
      .sort((a, b) => new Date(a.start) - new Date(b.start)); 
    saveRules(updated);
    setNewAtm({ id: '', start: '', end: '', capa: 6 });
  };

  const removeAtmRule = (id) => {
    const updated = { ...mappingRules };
    updated.atmMaster = updated.atmMaster.filter(atm => atm.id !== id);
    saveRules(updated);
  };

  return (
    <div className="flex h-screen bg-gray-50 font-sans">
      <aside className="w-64 bg-[#1a233a] text-gray-300 flex flex-col shadow-xl z-20">
        <div className="h-16 flex items-center px-6 bg-[#111827] border-b border-gray-700">
          <span className="text-xl font-bold text-white flex items-center gap-2">
            <Bot className="text-blue-400 w-6 h-6" /> Team AI Portal
          </span>
        </div>
        <nav className="flex-1 py-4">
          <p className="px-6 text-xs font-semibold text-gray-500 uppercase tracking-wider mb-2">Automation Tools</p>
          <ul className="space-y-1">
            <li>
              <button onClick={() => setActiveTab('fcst')} className={`w-full flex items-center gap-3 px-6 py-3 text-sm transition-colors ${activeTab === 'fcst' ? 'bg-blue-600/20 text-blue-400 border-r-4 border-blue-400 font-bold' : 'hover:bg-gray-800 hover:text-white'}`}>
                <CalendarDays className="w-4 h-4" /> FCST & LOT 스케줄러
              </button>
            </li>
            <li>
              <button onClick={() => setActiveTab('master')} className={`w-full flex items-center gap-3 px-6 py-3 text-sm transition-colors ${activeTab === 'master' ? 'bg-blue-600/20 text-blue-400 border-r-4 border-blue-400 font-bold' : 'hover:bg-gray-800 hover:text-white'}`}>
                <Database className="w-4 h-4" /> 관리자 (Master Data) 설정
              </button>
            </li>
          </ul>
        </nav>
      </aside>

      <main className="flex-1 flex flex-col overflow-hidden relative">
        <header className="h-16 bg-white shadow-sm flex items-center justify-between px-8 z-10 shrink-0">
          <h2 className="text-lg font-bold text-gray-800">
            {activeTab === 'fcst' ? 'FCST 자동 스케줄링 워크스페이스' : '시스템 관리자 설정 (데이터베이스)'}
          </h2>
          <div className="flex items-center gap-4 text-sm text-gray-500">
            <span className={`font-medium px-2 py-0.5 rounded border ${activeTab === 'fcst' ? 'bg-blue-50 text-blue-600 border-blue-100' : 'bg-green-50 text-green-600 border-green-100'}`}>
              {activeTab === 'fcst' ? '배정 모드' : 'Admin 편집 모드'}
            </span>
          </div>
        </header>

        {activeTab === 'fcst' && (
          <div className="flex-1 overflow-y-auto p-8 animate-in fade-in">
            <div className="max-w-6xl mx-auto space-y-6">
              <div className="bg-blue-50 border border-blue-100 rounded-lg p-4 flex gap-3 text-blue-800 text-sm">
                <AlertCircle className="w-5 h-5 flex-shrink-0 text-blue-500" />
                <p>고객사 엑셀 데이터를 복사하여 좌측에 붙여넣고 스케줄링을 실행하세요.</p>
              </div>

              <div className="grid grid-cols-2 gap-6">
                <div className="bg-white rounded-xl shadow-sm border border-gray-200 flex flex-col">
                  <div className="bg-gray-50 px-4 py-3 border-b flex items-center gap-2"><ClipboardPaste className="w-4 h-4 text-blue-600" /><h3 className="font-bold text-sm">STEP 1. 신규 FCST 데이터</h3></div>
                  <textarea className="w-full h-48 border-0 p-4 text-xs font-mono bg-transparent outline-none resize-none whitespace-pre" placeholder="엑셀 복사 후 붙여넣기..." onChange={(e) => setFcstInput(e.target.value)} value={fcstInput}/>
                </div>
                <div className="bg-white rounded-xl shadow-sm border border-gray-200 flex flex-col">
                  <div className="bg-gray-50 px-4 py-3 border-b flex items-center gap-2"><ClipboardPaste className="w-4 h-4 text-green-600" /><h3 className="font-bold text-sm">STEP 2. 기존 SOMP 데이터 (선택)</h3></div>
                  <textarea className="w-full h-48 border-0 p-4 text-xs font-mono bg-transparent outline-none resize-none whitespace-pre" placeholder="현재 배정 현황 엑셀 복사..." onChange={(e) => setSompInput(e.target.value)} value={sompInput}/>
                </div>
              </div>

              <div className="flex justify-center py-2">
                <button onClick={processData} disabled={status.type === 'loading'} className={`px-10 py-3.5 rounded-lg font-bold text-white flex items-center gap-2 shadow-lg transition-all ${status.type === 'loading' ? 'bg-gray-400 cursor-wait' : 'bg-blue-600 hover:bg-blue-700'}`}>
                  {status.type === 'loading' ? <><Loader2 className="w-5 h-5 animate-spin" /> 연산 중...</> : <><Play className="w-5 h-5" /> 자동 배정 시작</>}
                </button>
              </div>

              {status.message && status.type !== 'loading' && (
                <div className={`p-4 rounded-lg flex items-center gap-3 text-sm font-medium ${status.type === 'success' ? 'bg-green-50 text-green-800' : 'bg-red-50 text-red-800'}`}>
                  {status.type === 'success' ? <CheckCircle2 className="w-5 h-5"/> : <AlertCircle className="w-5 h-5"/>} {status.message}
                </div>
              )}

              {results.length > 0 && (
                <div className="bg-white rounded-xl shadow-md border overflow-hidden">
                  <div className="px-6 py-4 border-b flex justify-between items-center bg-gray-50">
                    <h3 className="font-bold flex items-center gap-2"><FileSpreadsheet className="w-5 h-5 text-gray-600" /> SOMP 업로드용 결과물</h3>
                    <button onClick={downloadExcel} className="flex items-center gap-2 px-4 py-2 bg-green-700 hover:bg-green-800 text-white text-sm font-bold rounded"><Download className="w-4 h-4" /> 엑셀 다운로드</button>
                  </div>
                  <div className="overflow-x-auto max-h-96">
                    <table className="w-full text-[11px] text-left text-gray-700 whitespace-nowrap">
                      <thead className="text-[10px] text-white bg-[#303387] sticky top-0 shadow-sm z-10">
                        <tr>{Object.keys(results[0]).map((h, i) => <th key={i} className={`px-4 py-2.5 border-r border-[#4044a5] font-semibold ${['납품일', '생산완료일', '출하가능일', '배정 LOT'].includes(h) ? 'bg-[#e63946]' : ''}`}>{h}</th>)}</tr>
                      </thead>
                      <tbody className="divide-y divide-gray-100">
                        {results.map((row, i) => {
                          const isWarning = row['비고'] !== '신규 자동배정'; // 정상 케이스가 아닌 경우 경고로 인식
                          return (
                            <tr key={i} className={`hover:bg-blue-50 transition-colors ${isWarning ? 'bg-red-50/20' : ''}`}>
                              {Object.entries(row).map(([key, val], j) => {
                                const isHighlight = key === '배정 LOT' && val.startsWith('ATM-');
                                // 필수로 채워져야 할 칸이 비어있으면 빨간 배경색으로 강조
                                const isEmptyError = val === '' && ['고객사', 'FAB', '모델', '배정 LOT'].includes(key);

                                return (
                                  <td key={j} className={`px-4 py-2 border-r border-gray-100 
                                    ${isHighlight ? 'font-bold text-blue-700 bg-blue-50/50' : ''} 
                                    ${isEmptyError ? 'bg-red-100/80' : ''}
                                    ${key === '비고' && isWarning ? 'text-red-500 font-bold' : ''}`
                                  }>
                                    {val}
                                  </td>
                                )
                              })}
                            </tr>
                          )
                        })}
                      </tbody>
                    </table>
                  </div>
                </div>
              )}
            </div>
          </div>
        )}

        {/* 탭 2. 마스터 데이터 편집기 */}
        {activeTab === 'master' && (
          <div className="flex-1 overflow-y-auto p-8 bg-gray-100 animate-in fade-in">
            <div className="max-w-6xl mx-auto space-y-8">
              <div className="bg-white p-5 rounded-lg border flex justify-between items-center shadow-sm">
                <div>
                  <h3 className="text-xl font-bold text-gray-800">단어장 및 스케줄 DB 에디터</h3>
                  <p className="text-sm text-gray-500 mt-1">이곳에서 추가/삭제한 데이터는 브라우저에 영구 저장되며 즉시 스케줄링 룰에 반영됩니다.</p>
                </div>
                <div className="bg-green-100 text-green-800 px-3 py-1.5 rounded-full text-xs font-bold flex items-center gap-1">
                  <Save size={14}/> 자동 저장 활성화됨
                </div>
              </div>

              {/* 1. 라인 매핑 */}
              <div className="bg-white rounded-xl shadow-sm border overflow-hidden">
                <div className="px-6 py-4 border-b bg-gray-50 flex items-center gap-2"><Building2 className="w-5 h-5 text-indigo-600" /><h4 className="font-bold text-gray-700">1. 고객사 라인명 매핑</h4></div>
                <div className="p-4">
                  <div className="flex gap-2 mb-4 p-3 bg-indigo-50 rounded-lg">
                    <input type="text" placeholder="고객사명 (예: Samsung)" className="flex-1 p-2 text-sm border rounded" value={newLine.client} onChange={e => setNewLine({...newLine, client: e.target.value})}/>
                    <input type="text" placeholder="입력 라인명 (예: P4F)" className="flex-1 p-2 text-sm border rounded" value={newLine.line} onChange={e => setNewLine({...newLine, line: e.target.value})}/>
                    <input type="text" placeholder="변환 FAB명 (예: SEC-P4(F))" className="flex-1 p-2 text-sm border rounded" value={newLine.fab} onChange={e => setNewLine({...newLine, fab: e.target.value})}/>
                    <button onClick={addLineRule} className="bg-indigo-600 text-white px-4 py-2 rounded font-bold flex items-center gap-1 hover:bg-indigo-700"><Plus size={16}/> 추가</button>
                  </div>
                  <div className="grid grid-cols-3 gap-2 max-h-60 overflow-y-auto">
                    {Object.entries(mappingRules.lineMap).map(([line, fab], idx) => (
                      <div key={idx} className="flex justify-between items-center p-2 border rounded hover:bg-gray-50 text-sm">
                        <div><span className="font-bold text-indigo-600">{line}</span> ➡️ {fab}</div>
                        <button onClick={() => removeLineRule(line)} className="text-gray-400 hover:text-red-500"><Trash2 size={16}/></button>
                      </div>
                    ))}
                  </div>
                </div>
              </div>

              {/* 2. 모델 매핑 */}
              <div className="bg-white rounded-xl shadow-sm border overflow-hidden">
                <div className="px-6 py-4 border-b bg-gray-50 flex items-center gap-2"><Cpu className="w-5 h-5 text-blue-600" /><h4 className="font-bold text-gray-700">2. 장비 모델명 매핑</h4></div>
                <div className="p-4">
                  <div className="flex gap-2 mb-4 p-3 bg-blue-50 rounded-lg">
                    <input type="text" placeholder="입력 모델명 (예: SUPRA-N-V)" className="flex-1 p-2 text-sm border rounded" value={newModel.raw} onChange={e => setNewModel({...newModel, raw: e.target.value})}/>
                    <input type="text" placeholder="변환 모델명 (예: SUPRA N)" className="flex-1 p-2 text-sm border rounded" value={newModel.somp} onChange={e => setNewModel({...newModel, somp: e.target.value})}/>
                    <input type="number" placeholder="PM수" className="w-24 p-2 text-sm border rounded" value={newModel.pm} onChange={e => setNewModel({...newModel, pm: e.target.value})}/>
                    <button onClick={addModelRule} className="bg-blue-600 text-white px-4 py-2 rounded font-bold flex items-center gap-1 hover:bg-blue-700"><Plus size={16}/> 추가</button>
                  </div>
                  <div className="grid grid-cols-3 gap-2 max-h-60 overflow-y-auto">
                    {Object.entries(mappingRules.modelMap).map(([raw, info], idx) => (
                      <div key={idx} className="flex justify-between items-center p-2 border rounded hover:bg-gray-50 text-sm">
                        <div><span className="font-bold text-blue-600">{raw}</span> ➡️ {info.model} (PM:{info.pm})</div>
                        <button onClick={() => removeModelRule(raw)} className="text-gray-400 hover:text-red-500"><Trash2 size={16}/></button>
                      </div>
                    ))}
                  </div>
                </div>
              </div>

              {/* 3. ATM 스케줄 */}
              <div className="bg-white rounded-xl shadow-sm border overflow-hidden">
                <div className="px-6 py-4 border-b bg-gray-50 flex items-center gap-2"><CalendarClock className="w-5 h-5 text-green-600" /><h4 className="font-bold text-gray-700">3. ATM 가동 스케줄 에디터</h4></div>
                <div className="p-4">
                  <div className="flex gap-2 mb-4 p-3 bg-green-50 rounded-lg">
                    <input type="text" placeholder="ATM 번호 (예: ATM-140)" className="flex-1 p-2 text-sm border rounded" value={newAtm.id} onChange={e => setNewAtm({...newAtm, id: e.target.value})}/>
                    <input type="date" className="flex-1 p-2 text-sm border rounded text-gray-600" value={newAtm.start} onChange={e => setNewAtm({...newAtm, start: e.target.value})}/>
                    <input type="date" className="flex-1 p-2 text-sm border rounded text-gray-600" value={newAtm.end} onChange={e => setNewAtm({...newAtm, end: e.target.value})}/>
                    <input type="number" placeholder="Capa" className="w-20 p-2 text-sm border rounded" value={newAtm.capa} onChange={e => setNewAtm({...newAtm, capa: e.target.value})}/>
                    <button onClick={addAtmRule} className="bg-green-600 text-white px-4 py-2 rounded font-bold flex items-center gap-1 hover:bg-green-700"><Plus size={16}/> 추가</button>
                  </div>
                  <div className="overflow-x-auto">
                    <table className="w-full text-sm text-left">
                      <thead className="bg-gray-100 text-gray-700 border-b">
                        <tr><th className="px-4 py-2">ATM 번호</th><th className="px-4 py-2">시작일</th><th className="px-4 py-2">종료일</th><th className="px-4 py-2">Capa</th><th className="px-4 py-2">삭제</th></tr>
                      </thead>
                      <tbody>
                        {mappingRules.atmMaster.map((atm, idx) => (
                          <tr key={idx} className="border-b hover:bg-gray-50">
                            <td className="px-4 py-2 font-bold text-gray-800">{atm.id}</td>
                            <td className="px-4 py-2 text-gray-600">{atm.start}</td>
                            <td className="px-4 py-2 text-gray-600">{atm.end}</td>
                            <td className="px-4 py-2 text-green-700 font-medium">{atm.maxCapa}</td>
                            <td className="px-4 py-2"><button onClick={() => removeAtmRule(atm.id)} className="text-gray-400 hover:text-red-500"><Trash2 size={16}/></button></td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </div>
              </div>

            </div>
          </div>
        )}
      </main>
    </div>
  );
}
